        raise ValueError("n must be a positive integer")

    def is_prime(num: int) -> bool:
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        for i in range(3, int(num**0.5) + 1, 2):
            if num % i == 0:
                return False
        return True

    def is_fibonacci(num: int) -> bool:
        if num < 0:
            return False
        if num == 0:
            return True
        if num == 1:
            return True
        for i in range(2, num + 1):
            if num - i >= 0:
                if is_fibonacci(i) and is_fibonacci(num - i):
                    return True
        return False

    fibs = [0, 1]
    while len(fibs) < n:
        fibs.append(fibs[-1] + fibs[-2])

    result = None
    for num in fibs:
        if is_prime(num):
            result = num
            break

    return result

